(()=>{'use strict';const base='/DraBornGarage/assets/chunks_v3/';const modules=[['dkd_core.js',10,'9b0878cae0bb39dc87fa6593558eab7016980c04fa971cb6f34e1db774917ac5'],['dkd_customer.js',5,'eed5f5514c2143e9ea7e8d6cdda442e0af50b0d3fb747cc9010f6ed08a2059e1'],['dkd_staff.js',12,'2d284f923827298df993b87bd8dda2ff520b5286c39a5ea5b4a0d69bc83b5846'],['dkd_garage.js',1,'57c52d1e1e8a3c61e32ebb3574d32d265b0c0a95b9e0142aa50fe012855af4b6']];const prefix=n=>n.replace('dkd_','').replace('.js','');async function inflate(encoded){const bytes=Uint8Array.from(atob(encoded),c=>c.charCodeAt(0));if(!('DecompressionStream'in window))throw new Error('Tarayıcınız DraBornGarage web paketini açmak için çok eski.');return new Response(new Blob([bytes]).stream().pipeThrough(new DecompressionStream('gzip'))).text()}async function hash(text){const bytes=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(text));return[...new Uint8Array(bytes)].map(v=>v.toString(16).padStart(2,'0')).join('')}(async()=>{for(const[name,count,expected]of modules){let encoded='';for(let i=0;i<count;i++){const chunk=`${prefix(name)}_${String(i).padStart(3,'0')}.txt`;const response=await fetch(base+chunk,{cache:'no-cache'});if(!response.ok)throw new Error(`${name} paketi yüklenemedi (${response.status}).`);encoded+=(await response.text()).trim()}const source=await inflate(encoded);if(await hash(source)!==expected)throw new Error(`${name} bütünlük kontrolü başarısız.`);(0,eval)(`${source}\n//# sourceURL=/DraBornGarage/assets/${name}`)}})().catch(error=>{console.error(error);const app=document.getElementById('dkd-app');if(app)app.innerHTML=`<div class="dkd-section"><div class="dkd-empty"><div class="ico">⚠</div><h1>Web paketi açılamadı</h1><p>${String(error.message||error)}</p><button class="dkd-btn" onclick="location.reload()">Tekrar Dene</button></div></div>`})})();
